import { useState } from "react";

import Sidebar from "../components/common/Sidebar";

function FacultyLayout({
  children
}) {

  const [isOpen,
    setIsOpen] =
    useState(false);

  return (
    <div>

      <div
        style={{
          height: "60px",
          background: "#2563eb",
          color: "white",
          display: "flex",
          alignItems: "center",
          padding: "0 20px"
        }}
      >
        <button
          onClick={() =>
            setIsOpen(
              !isOpen
            )
          }
          style={{
            fontSize: "24px",
            background:
              "transparent",
            border: "none",
            color: "white",
            cursor: "pointer"
          }}
        >
          ☰
        </button>

        <h2
          style={{
            marginLeft:
              "20px"
          }}
        >
          SRIHER IQAC Portal
        </h2>
      </div>

      <Sidebar
        role="faculty"
        isOpen={isOpen}
        setIsOpen={
          setIsOpen
        }
      />

      <div
        style={{
          padding: "20px"
        }}
      >
        {children}
      </div>

    </div>
  );
}

export default FacultyLayout;
